let editor;
let abortController = null;

// Initialize Monaco Editor
require.config({ paths: { vs: 'https://cdnjs.cloudflare.com/ajax/libs/monaco-editor/0.39.0/min/vs' } });
require(['vs/editor/editor.main'], function () {
    editor = monaco.editor.create(document.getElementById('editor-container'), {
        value: [
            '.doctype {paged}',
            '.docname {My AI Document}',
            '.docauthor {Ollama AI}',
            '',
            '# Hello World',
            '',
            'This is a LayerDocs document generated by AI.',
            '',
            '.box {Tips} type:{tip}',
            '    LayerDocs is powerful!'
        ].join('\n'),
        language: 'markdown',
        theme: 'vs-dark',
        automaticLayout: true,
        fontFamily: "'Fira Code', monospace",
        fontSize: 14,
        minimap: { enabled: false },
        lineNumbers: 'on',
        scrollBeyondLastLine: false,
        padding: { top: 10 }
    });
});

// Load Ollama Models
async function loadModels() {
    try {
        const res = await fetch('/api/models');
        const data = await res.json();
        const select = document.getElementById('model-select');
        select.innerHTML = '';
        
        if (data.models && data.models.length > 0) {
            data.models.forEach(model => {
                const opt = document.createElement('option');
                opt.value = model.name;
                opt.textContent = model.name;
                select.appendChild(opt);
            });
        } else {
            select.innerHTML = '<option value="">No models found</option>';
        }
    } catch (e) {
        document.getElementById('model-select').innerHTML = '<option value="">Ollama Offline</option>';
    }
}

// Compile LayerDocs
async function compile() {
    const overlay = document.getElementById('compiling-overlay');
    overlay.classList.remove('hidden');
    
    try {
        const code = editor.getValue();
        const res = await fetch('/api/compile', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ code })
        });
        const data = await res.json();
        
        if (data.url) {
            const iframe = document.getElementById('preview-frame');
            iframe.src = data.url;
        } else {
            alert('Compilation failed: ' + (data.error || 'Unknown error'));
        }
    } catch (e) {
        alert('Error connecting to server: ' + e.message);
    } finally {
        overlay.classList.add('hidden');
    }
}

// Chat with AI
async function sendMessage() {
    const input = document.getElementById('chat-input');
    const prompt = input.value.trim();
    const model = document.getElementById('model-select').value;
    
    if (!prompt || !model) return;
    
    addMessage(prompt, 'user');
    input.value = '';
    
    const assistantMsg = addMessage('Thinking...', 'assistant');
    let aiResponse = '';
    
    abortController = new AbortController();
    
    try {
        const response = await fetch('/api/chat', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                model: model,
                prompt: `You are an expert in LayerDocs syntax. 
                LayerDocs uses .function {arg} syntax.
                Provide only the LayerDocs code if asked to write a document.
                The user wants: ${prompt}`,
                stream: true
            }),
            signal: abortController.signal
        });
        
        const reader = response.body.getReader();
        const decoder = new TextDecoder();
        
        while (true) {
            const { done, value } = await reader.read();
            if (done) break;
            
            const chunk = decoder.decode(value, { stream: true });
            const lines = chunk.split('\n');
            
            for (const line of lines) {
                if (!line.trim()) continue;
                const json = JSON.parse(line);
                if (json.response) {
                    aiResponse += json.response;
                    assistantMsg.textContent = aiResponse;
                    
                    // If AI sends code blocks, extract and put in editor
                    if (aiResponse.includes('```')) {
                        const codeMatch = aiResponse.match(/```(?:markdown|qd)?\n([\s\S]*?)```/);
                        if (codeMatch) {
                            editor.setValue(codeMatch[1].trim());
                        }
                    }
                }
            }
        }
    } catch (e) {
        if (e.name === 'AbortError') {
            assistantMsg.textContent += ' [Stopped]';
        } else {
            assistantMsg.textContent = 'Error: ' + e.message;
        }
    } finally {
        abortController = null;
    }
}

function addMessage(text, role) {
    const chat = document.getElementById('chat-messages');
    const msg = document.createElement('div');
    msg.className = `message ${role}`;
    msg.textContent = text;
    chat.appendChild(msg);
    chat.scrollTop = chat.scrollHeight;
    return msg;
}

// Event Listeners
document.getElementById('compile-btn').addEventListener('click', compile);
document.getElementById('send-btn').addEventListener('click', sendMessage);
document.getElementById('stop-btn').addEventListener('click', () => {
    if (abortController) abortController.abort();
});
document.getElementById('chat-input').addEventListener('keydown', (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
        e.preventDefault();
        sendMessage();
    }
});

// Start
loadModels();
setInterval(loadModels, 10000); // Refresh models every 10s
